from flask import Flask
from flask_graphql import GraphQLView
from graphene import ObjectType, String, Int, Float, List, Field, Schema, Boolean
from datetime import datetime

app = Flask(__name__)

# Mock data
PRODUCTS = [
    {"id": 1, "name": "Laptop", "price": 999.99, "category_id": 1, "description": "High-performance laptop"},
    {"id": 2, "name": "Mouse", "price": 29.99, "category_id": 2, "description": "Wireless mouse"},
    {"id": 3, "name": "Keyboard", "price": 79.99, "category_id": 2, "description": "Mechanical keyboard"},
]

CATEGORIES = [
    {"id": 1, "name": "Computers", "description": "Computer systems and laptops"},
    {"id": 2, "name": "Accessories", "description": "Computer accessories"},
]

REVIEWS = [
    {"id": 1, "product_id": 1, "user_name": "John Doe", "rating": 5, "comment": "Excellent product!", "date": "2024-01-15"},
    {"id": 2, "product_id": 1, "user_name": "Jane Smith", "rating": 4, "comment": "Good value", "date": "2024-01-20"},
    {"id": 3, "product_id": 2, "user_name": "Bob Johnson", "rating": 5, "comment": "Perfect mouse", "date": "2024-01-18"},
]

# GraphQL Types
class ReviewType(ObjectType):
    id = Int()
    product_id = Int()
    user_name = String()
    rating = Int()
    comment = String()
    date = String()

class ProductType(ObjectType):
    id = Int()
    name = String()
    price = Float()
    category_id = Int()
    description = String()
    reviews = List(ReviewType)

    def resolve_reviews(self, info):
        return [r for r in REVIEWS if r['product_id'] == self.id]

class CategoryType(ObjectType):
    id = Int()
    name = String()
    description = String()
    products = List(ProductType)

    def resolve_products(self, info):
        return [p for p in PRODUCTS if p['category_id'] == self.id]

# Query with depth limiting and complexity analysis
class Query(ObjectType):
    products = List(ProductType, limit=Int(default_value=10))
    product = Field(ProductType, id=Int(required=True))
    categories = List(CategoryType, limit=Int(default_value=10))
    category = Field(CategoryType, id=Int(required=True))
    reviews = List(ReviewType, product_id=Int(), limit=Int(default_value=10))

    def resolve_products(self, info, limit=10):
        # Enforce maximum limit
        limit = min(limit, 100)
        return PRODUCTS[:limit]

    def resolve_product(self, info, id):
        return next((p for p in PRODUCTS if p['id'] == id), None)

    def resolve_categories(self, info, limit=10):
        # Enforce maximum limit
        limit = min(limit, 100)
        return CATEGORIES[:limit]

    def resolve_category(self, info, id):
        return next((c for c in CATEGORIES if c['id'] == id), None)

    def resolve_reviews(self, info, product_id=None, limit=10):
        # Enforce maximum limit
        limit = min(limit, 100)
        if product_id:
            return [r for r in REVIEWS if r['product_id'] == product_id][:limit]
        return REVIEWS[:limit]

# Depth limiting middleware
class DepthAnalysisMiddleware:
    def __init__(self, max_depth=5):
        self.max_depth = max_depth

    def resolve(self, next, root, info, **args):
        depth = 0
        current = info.path
        while current:
            depth += 1
            current = getattr(current, 'prev', None)
        
        if depth > self.max_depth:
            raise Exception(f"Query depth exceeds maximum allowed depth of {self.max_depth}")
        
        return next(root, info, **args)

# Create schema with security configurations
schema = Schema(query=Query)

# Configure GraphQL view with security settings
app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=False,  # Disable GraphiQL in production
        middleware=[DepthAnalysisMiddleware(max_depth=5)],
        # Disable introspection for production
        introspection=False
    )
)

# Separate endpoint for development with introspection enabled
