    app.add_url_rule(
        '/graphql-dev',
        view_func=GraphQLView.as_view(
            'graphql-dev',
            schema=schema,
            graphiql=True,
            middleware=[DepthAnalysisMiddleware(max_depth=5)],
            introspection=True
        )
    )

